import React, { useEffect, useState } from "react";
import axios from "../api"; // Make sure this points to your api.js

const SearchForm = () => {
  const [districts, setDistricts] = useState([]);
  const [formData, setFormData] = useState({ district: "" });

  // Fetch districts from backend
  useEffect(() => {
    axios.get("/districts/")
      .then(res => {
        console.log("Districts fetched:", res.data); // Check console
        setDistricts(res.data);
      })
      .catch(err => console.error("Error fetching districts:", err));
  }, []);

  // Handle select change
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <form>
      <h2>Bhulekh Land Records</h2>

      <label>District:</label>
      <select
        name="district"
        value={formData.district}
        onChange={handleChange}
      >
        <option value="">--निवडा--</option>
        {districts.map(d => (
          <option key={d.id} value={d.id}>{d.name}</option>
        ))}
      </select>
    </form>
  );
};

export default SearchForm;
